                     if matrix.get(cat_data['id'], {}).get(platform, {}).get('state') == '確定')
excluded_total = sum(1 for cat_data in categories for platform in platforms 
                    if matrix.get(cat_data['id'], {}).get(platform, {}).get('state') == '対象外')

