print(f"Platforms: {len(platforms)}")
print(f"Total cells: {total_cells}")
print(f"Uncollected cells: {uncollected_total}")
print(f"Excluded cells: {excluded_total} (improper reasons: {len(excluded_reason_issues)})")
print(f"Confirmed cells: {confirmed_total} (qa_ref issues: {len(confirmed_qa_ref_issues)})")
print(f"Category_aggregate issues: {len(aggregate_issues)}")
print(f"Platform existence issues: {len(platform_existence_issues)}")

print("\n=== FOUNDATION TRACE (serves_goals) ===")
goal_ids = [g['id'] for g in serves_goals]
print(f"Available goals in requirements_foundation: {goal_ids}")
print(f"Total goals defined: {len(goal_ids)}")

# Check if serves_goals in cells reference defined goals
undefined_goal_refs = set()
for cat_data in categories:
    cat_id = cat_data['id']
    for platform in platforms:
        cell = matrix.get(cat_id, {}).get(platform, {})
        cell_goal_refs = cell.get('serves_goals', [])
        for ref in cell_goal_refs:
            if ref not in goal_ids:
                undefined_goal_refs.add(ref)

if undefined_goal_refs:
    print(f"WARNING: cells reference undefined goals: {undefined_goal_refs}")
else:
    print(f"All serves_goals references valid. ✓")

